export class NotFoundError extends Error{name="NotFoundError";code="ENOENT";constructor(message){super(`ENOENT: No such file or directory, ${message}`);}}
export class PermissionError extends Error{name="PermissionError";code="EPERM";constructor(message){super(`EPERM: Operation not permitted, ${message}`);}}
export class DirectoryError extends Error{name="DirectoryError";code="EISDIR";constructor(message){super(`EISDIR: Illegal operation on a directory, ${message}`);}}
export class NotEmptyError extends Error{name="NotEmptyError";code="ENOTEMPTY";constructor(message){super(`ENOTEMPTY: Directory not empty, ${message}`);}}